INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07480', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列那一句話是採焦點解決短期處遇（Solution-focused brief treatment, SFBT）工作者的問話？', '["「你記得最近一次勇敢拒絕老闆不合理要求是什麼時候？」", "「上週你太太碎碎念時，你竟然沒有生氣罵人，為什麼啊？」", "「你為何會認為你天生就是笨呢？」", "「你說與女友個性不合，以致相處痛苦，可以舉個例子嗎？」"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 18, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07481', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '莫拉克風災後各地的捐款湧進災區幫忙賑災與重整家園，但幾個月後捐款數目就逐漸減少，社會大眾也 漸漸遺忘還在打拼重建家園的民眾。社會工作員在協助民眾發展新資源時，應該：', '["讓災區民眾扮演主導角色，因為他們是當事人", "讓社會工作員扮演主導角色，因為他們具有專業", "讓政府相關單位扮演主導角色，因為他們有調撥協調資源的能力", "讓捐贈的團體扮演主導角色，因為他們是資源提供者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07482', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '青少年向社會工作員抱怨：「我父親老是不放心我，老是問我到那裡去了？搭什麼車去的？去的地方安 不安全？老是把我當三歲小孩看待。」社會工作員的同理回應，下列何者最適切？', '["「你覺得不高興、不滿和生氣，甚至有些挫折和憤怒。」", "「你不高興、不滿、生氣你父親對你的不信任，你認為自己可以照顧自己。」", "「你不高興、不滿或生氣你父親對你的不信任，我為你感到難過。」", "「你過去一定做過什麼令他擔憂的事？他會有這樣的態度也是自然的。」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07483', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '案主：「我只覺得情緒低落，因為丈夫常批評我一事無成，我認為他說的也沒錯，我就是無法把事情做 好，小兒子摔傷我要負責任。」下列何者是工作者最適當的真誠回應？', '["「我有時候也會覺得情緒低落，所以也可以了解妳的感受，雖然妳也不想被別人的批評所影響，但是 有時候也沒有那麼容易。」", "「妳的事讓我覺得傷心，我也有類似的經驗，碰到被指責和貶抑的事情會讓我感到情緒低落，我想不 被影響，卻又沒有那麼容易。」", "「我有時候也會覺得很沒有價值，情緒不佳，好像整天都不順利，尤其是碰到和妳類似的情境的時候， 所以我可以了解妳的感受。」", "「我也常常碰到這樣的事情，可以了解妳的心情，總是覺得不公平，尤其是在這個父權的世界裡，男 人都以為自己很了不起。」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07484', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '艾理斯（Ellis）提出的理性情緒治療法，基本信念是ABC理論，A是環境中的引發事件，通常是不愉快事 件，B是人對自己和引發事件的信念、想法和內在自言或心像，C是「信念、想法、自言等的情緒結果」， 就該理論而言，下列何者是錯誤的？', '["ABC三者可能交互影響", "當B（認知信念或想法）是理性的，則情緒和行為是健全的，當這些認知不是理性的，將直接導致失能 的情緒和行為", "不愉快事件直接造成負向的情緒，對事件的想法並不重要", "ABC的模式，可以應用在個人，也可以應用在團體和家庭處遇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07485', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '案主抱怨：「我丈夫經常要加班，過度專注在工作，一點也不重視家庭生活，只會透過電話簡短交談， 都沒有注意到我的感受。」以下是社會工作者的同理心回應，那一個同理心回應的層次是最高或者最深 入的？', '["妳因為先生工作不常見面，無法體貼妳重視夫妻關係的心意，覺得生氣與無奈", "妳先生是因為工作忙才沒有時間，他應該是為了家庭打拼，多體諒他吧", "妳對於丈夫加班無法和妳相處感到生氣和挫折，已經不太確定他是不是真的在意妳的感受，甚至懷疑 他是不是還愛著妳", "妳的經驗我也有過，會讓人覺得無奈、挫折、生氣，甚至會覺得自卑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07486', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '規範倫理學之中的「目的論」也是解決社會工作倫理兩難議題的重要參考架構，以下何者不屬於目的論 的論述？', '["最大效益：倫理抉擇的原則之一是「為最大多數的眾人帶來最大的效益」", "規則效益：違反或遵守倫理規範或規則對於社工和案主互動關係的影響", "最小傷害：倫理抉擇以選擇最小的傷害為原則", "義務目的：遵守倫理規範的目的就是善盡義務，為了義務而義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07487', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作倫理的學者Frederic Reamer提供了一個解決倫理兩難的架構和步驟，請針對下列步驟依先後次', '["釐清倫理的議題，找出所有可能被倫理抉擇影響到的個人團體和組織", "徵詢同儕以及 專家的意見", "嘗試找出各種可採取的行動以及參與者，並評估每種行動的利弊得失", "做抉擇並記錄 抉擇的過程，監督評估和記錄抉擇的結果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07488', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關家庭的評估和處遇，下列何者是錯誤的？', '["家庭傾向於維持原有的樣貌，想改變家庭並不是一件容易的工作", "家庭規則常是隱性的，必須從觀察家庭互動過程之中進行辨識", "疏離鬆散的家庭或者過度緊密糾結的家庭一定是失去功能的家庭", "家庭初次會談使用加入法（joining），是指尊重家庭的規則與互動方式，即使威權的父親是需要改變的 對象，也必須事先尊重家庭的權力順位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07489', 'social-worker', 'social-worker-moex-100-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '薩提爾（Satir）提出家庭的三角關係，以下何者是正確的？', '["家庭如果只有夫妻兩人，通常不會出現三角關係", "過世的親人不會是構成三角關係的一員", "家庭成員越多，三角關係就越多，也越複雜", "三角關係對成員的影響都是負面的，沒有正向"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "4a84634809c5", "answer_pdf_sha1": "a5123f6d0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
